import type { Metadata } from "next";

import { AttendanceClient } from "./AttendanceClient";

export const metadata: Metadata = {
  title: "出欠管理 | 校務支援システム",
  description:
    "担任が学級の日々の出欠を記録・確認し、慢性的な欠席を把握するための出欠管理画面。",
};

export default function AttendancePage() {
  return (
    <main className="min-h-screen bg-background text-foreground">
      <AttendanceClient />
    </main>
  );
}

"use client";

import * as React from "react";
import {
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Cluster,
  Container,
  DistributionBar,
  EmptyState,
  Meter,
  ScheduleGrid,
  Select,
  Sheet,
  SheetContent,
  SheetDescription,
  SheetFooter,
  SheetHeader,
  SheetTitle,
  Statistic,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  Textarea,
  ToggleGroup,
  ToggleGroupItem,
  VStack,
} from "@gunjo/ui";
import type { ScheduleAxisItem, ScheduleCell } from "@gunjo/ui";

import { CLASS_LABEL, DAYS, INITIAL_RECORDS, STUDENTS } from "./data";
import {
  REASON_LABEL,
  REASON_ORDER,
  STATUS_META,
  STATUS_ORDER,
} from "./statusMeta";
import { computeDailySummary, computeStudentStats } from "./stats";
import type {
  AbsenceReason,
  AttendanceMap,
  AttendanceStatus,
} from "./types";

/** マトリクスのセル本文（記号 + 略字）。色だけに頼らない。 */
function CellBody({ status }: { status: AttendanceStatus }) {
  const meta = STATUS_META[status];
  return (
    <span className="flex flex-col items-center justify-center gap-0.5 leading-none">
      <span aria-hidden className="text-lg font-bold tabular-nums">
        {meta.glyph}
      </span>
      <span className="text-[10px] font-medium text-muted-foreground">
        {meta.label}
      </span>
    </span>
  );
}

interface SelectedCell {
  studentId: string;
  dayId: string;
}

export function AttendanceClient() {
  const [records, setRecords] = React.useState<AttendanceMap>(INITIAL_RECORDS);
  const [view, setView] = React.useState<"matrix" | "roster">("matrix");

  // 入力シート（出欠入力）の状態
  const [selected, setSelected] = React.useState<SelectedCell | null>(null);
  const [draftStatus, setDraftStatus] =
    React.useState<AttendanceStatus>("present");
  const [draftReason, setDraftReason] = React.useState<AbsenceReason | "">("");
  const [draftMemo, setDraftMemo] = React.useState("");

  // 日次サマリで見る日
  const openDayIds = React.useMemo(
    () => DAYS.filter((d) => !d.closed).map((d) => d.id),
    [],
  );
  const [summaryDayId, setSummaryDayId] = React.useState<string>(
    openDayIds[openDayIds.length - 1],
  );

  const openSheet = React.useCallback(
    (studentId: string, dayId: string) => {
      const rec = records[studentId]?.[dayId];
      setSelected({ studentId, dayId });
      setDraftStatus(rec?.status ?? "present");
      setDraftReason(rec?.note?.reason ?? "");
      setDraftMemo(rec?.note?.memo ?? "");
    },
    [records],
  );

  const closeSheet = React.useCallback(() => setSelected(null), []);

  const saveDraft = React.useCallback(() => {
    if (!selected) return;
    const { studentId, dayId } = selected;
    const needsNote = draftStatus !== "present";
    setRecords((prev) => ({
      ...prev,
      [studentId]: {
        ...prev[studentId],
        [dayId]: {
          status: draftStatus,
          note: needsNote
            ? {
                reason: draftReason || undefined,
                memo: draftMemo.trim() || undefined,
              }
            : undefined,
        },
      },
    }));
    setSelected(null);
  }, [selected, draftStatus, draftReason, draftMemo]);

  // --- マトリクス（ScheduleGrid）の軸とセル ---
  const columns: ScheduleAxisItem[] = React.useMemo(
    () =>
      DAYS.map((d) => ({
        id: d.id,
        label: d.short,
        sublabel: d.closed ? d.closedLabel : `(${d.weekday})`,
        ariaLabel: `${d.short} ${d.weekday}曜日`,
      })),
    [],
  );

  const stats = React.useMemo(
    () =>
      Object.fromEntries(
        STUDENTS.map((s) => [
          s.id,
          computeStudentStats(s.id, records, DAYS),
        ]),
      ),
    [records],
  );

  const rows: ScheduleAxisItem[] = React.useMemo(
    () =>
      STUDENTS.map((s) => ({
        id: s.id,
        label: `${s.number}`,
        sublabel: s.name.split(" ")[0],
        ariaLabel: `出席番号${s.number}番 ${s.name}`,
      })),
    [],
  );

  const cells: ScheduleCell[] = React.useMemo(() => {
    const out: ScheduleCell[] = [];
    for (const student of STUDENTS) {
      for (const day of DAYS) {
        if (day.closed) {
          out.push({
            rowId: student.id,
            colId: day.id,
            unavailable: true,
          });
          continue;
        }
        const rec = records[student.id]?.[day.id];
        const status = rec?.status ?? "present";
        const meta = STATUS_META[status];
        const reasonText = rec?.note?.reason
          ? `、理由: ${REASON_LABEL[rec.note.reason]}`
          : "";
        out.push({
          rowId: student.id,
          colId: day.id,
          tone: meta.cellTone,
          content: <CellBody status={status} />,
          description: `${student.name} ${meta.label}${reasonText}（タップで変更）`,
          onSelect: () => openSheet(student.id, day.id),
        });
      }
    }
    return out;
  }, [records, openSheet]);

  // --- クラス全体のサマリ（在籍×全授業日のステータス内訳） ---
  const classTotals = React.useMemo(() => {
    const totals: Record<AttendanceStatus, number> = {
      present: 0,
      absent: 0,
      late: 0,
      earlyLeave: 0,
      official: 0,
      suspended: 0,
    };
    for (const s of STUDENTS) {
      const st = stats[s.id];
      totals.present += st.present;
      totals.absent += st.absent;
      totals.late += st.late;
      totals.earlyLeave += st.earlyLeave;
      totals.official += st.official;
      totals.suspended += st.suspended;
    }
    return totals;
  }, [stats]);

  const atRiskCount = React.useMemo(
    () => STUDENTS.filter((s) => stats[s.id].atRisk).length,
    [stats],
  );

  const classRate = React.useMemo(() => {
    let attended = 0;
    let counted = 0;
    for (const s of STUDENTS) {
      const st = stats[s.id];
      attended += st.present + st.late + st.earlyLeave;
      counted += st.countedDays;
    }
    return counted > 0 ? Math.round((attended / counted) * 1000) / 10 : null;
  }, [stats]);

  // --- 日次サマリ ---
  const daily = React.useMemo(
    () => computeDailySummary(summaryDayId, records, STUDENTS),
    [summaryDayId, records],
  );
  const summaryDay = DAYS.find((d) => d.id === summaryDayId);

  const selectedStudent = selected
    ? STUDENTS.find((s) => s.id === selected.studentId)
    : null;
  const selectedDay = selected
    ? DAYS.find((d) => d.id === selected.dayId)
    : null;
  const draftNeedsNote = draftStatus !== "present";

  return (
    <Container size="2xl" className="py-6 sm:py-8">
      <VStack gap={6}>
        {/* ===== ヘッダー ===== */}
        <header>
          <Cluster justify="between" align="end" gap={3}>
            <div>
              <h1 className="text-2xl font-bold tracking-tight sm:text-3xl">
                出欠管理
              </h1>
              <p className="mt-1 text-sm text-muted-foreground">
                {CLASS_LABEL}・2026 年 6 月（第 1〜2 週）／担任: 佐藤 先生
              </p>
            </div>
            <Badge variant={atRiskCount > 0 ? "warning" : "success"}>
              要注意 {atRiskCount} 名
            </Badge>
          </Cluster>
        </header>

        {/* ===== サマリ統計 ===== */}
        <section aria-label="クラス全体の統計">
          <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
            <Statistic
              label="クラス出席率"
              value={classRate !== null ? `${classRate}%` : "—"}
              hint="公欠・出停・休校を除く"
            />
            <Statistic
              label="延べ欠席"
              value={`${classTotals.absent} 回`}
              trend={classTotals.absent > 0 ? "down" : "flat"}
              tone={classTotals.absent > 0 ? "negative" : "neutral"}
            />
            <Statistic
              label="延べ遅刻・早退"
              value={`${classTotals.late + classTotals.earlyLeave} 回`}
            />
            <Statistic
              label="要注意の生徒"
              value={`${atRiskCount} 名`}
              tone={atRiskCount > 0 ? "negative" : "neutral"}
              hint="出席率<90% または 欠席3回以上"
            />
          </div>
        </section>

        {/* ===== 凡例 ===== */}
        <section aria-label="凡例">
          <Card>
            <CardContent className="p-4">
              <Cluster gap={4} align="center">
                <span className="text-xs font-medium text-muted-foreground">
                  凡例
                </span>
                {STATUS_ORDER.map((status) => {
                  const meta = STATUS_META[status];
                  return (
                    <Cluster key={status} gap={1} align="center">
                      <Badge variant={meta.badge}>
                        <span aria-hidden className="mr-1">
                          {meta.glyph}
                        </span>
                        {meta.label}
                      </Badge>
                    </Cluster>
                  );
                })}
              </Cluster>
            </CardContent>
          </Card>
        </section>

        {/* ===== ビュー切替: マトリクス / 名簿 ===== */}
        <Tabs
          value={view}
          onValueChange={(v) => setView(v as "matrix" | "roster")}
        >
          <TabsList>
            <TabsTrigger value="matrix">出欠マトリクス</TabsTrigger>
            <TabsTrigger value="roster">名簿・出席率</TabsTrigger>
          </TabsList>

          {/* --- マトリクス --- */}
          <TabsContent value="matrix">
            <VStack gap={3}>
              <p className="text-sm text-muted-foreground">
                行 = 生徒（出席番号）、列 = 日付。セルを選んで（クリック /
                Enter）状態を変更できます。矢印キーでセル間を移動できます。
              </p>
              <ScheduleGrid
                label={`${CLASS_LABEL} 出欠マトリクス`}
                cornerLabel="番号"
                rows={rows}
                columns={columns}
                cells={cells}
                rowHeaderWidth={84}
                minColumnWidth={72}
                unavailableLabel="休校"
              />
              <p className="text-xs text-muted-foreground">
                ◯ 出席 / ✕ 欠席 / △ 遅刻 / ▽ 早退 / 公 公欠 / 停 出席停止
              </p>
            </VStack>
          </TabsContent>

          {/* --- 名簿 + 出席率 --- */}
          <TabsContent value="roster">
            <Card>
              <div className="overflow-x-auto">
                <table className="w-full border-collapse text-sm">
                  <caption className="sr-only">
                    生徒ごとの出席率と欠席・遅刻・早退の回数
                  </caption>
                  <thead>
                    <tr className="border-b border-border text-left text-xs text-muted-foreground">
                      <th scope="col" className="px-3 py-2 font-medium">
                        番号
                      </th>
                      <th scope="col" className="px-3 py-2 font-medium">
                        氏名
                      </th>
                      <th
                        scope="col"
                        className="px-3 py-2 font-medium min-w-[160px]"
                      >
                        出席率
                      </th>
                      <th
                        scope="col"
                        className="px-3 py-2 text-right font-medium"
                      >
                        欠席
                      </th>
                      <th
                        scope="col"
                        className="px-3 py-2 text-right font-medium"
                      >
                        遅刻
                      </th>
                      <th
                        scope="col"
                        className="px-3 py-2 text-right font-medium"
                      >
                        早退
                      </th>
                      <th scope="col" className="px-3 py-2 font-medium">
                        状態
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    {STUDENTS.map((student) => {
                      const st = stats[student.id];
                      return (
                        <tr
                          key={student.id}
                          className="border-b border-border/60 last:border-0"
                        >
                          <td className="px-3 py-2 tabular-nums text-muted-foreground">
                            {student.number}
                          </td>
                          <th
                            scope="row"
                            className="px-3 py-2 text-left font-medium"
                          >
                            {student.name}
                          </th>
                          <td className="px-3 py-2">
                            {st.attendanceRate !== null ? (
                              <Meter
                                size="inline"
                                value={st.attendanceRate}
                                max={100}
                                direction="higher-is-better"
                                target={90}
                                label={`${student.name} の出席率`}
                              />
                            ) : (
                              <span className="text-xs text-muted-foreground">
                                算入対象なし
                              </span>
                            )}
                          </td>
                          <td className="px-3 py-2 text-right tabular-nums">
                            {st.absent}
                          </td>
                          <td className="px-3 py-2 text-right tabular-nums">
                            {st.late}
                          </td>
                          <td className="px-3 py-2 text-right tabular-nums">
                            {st.earlyLeave}
                          </td>
                          <td className="px-3 py-2">
                            {st.atRisk ? (
                              <Badge variant="warning">要注意</Badge>
                            ) : (
                              <Badge variant="success">良好</Badge>
                            )}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </Card>
          </TabsContent>
        </Tabs>

        {/* ===== 日次サマリ ===== */}
        <section aria-labelledby="daily-summary-heading">
          <Card>
            <CardHeader>
              <Cluster justify="between" align="end" gap={3}>
                <div>
                  <CardTitle as="h2" id="daily-summary-heading">
                    日次サマリ
                  </CardTitle>
                  <CardDescription>
                    選んだ日のクラス全体の出欠内訳
                  </CardDescription>
                </div>
                <div className="w-40">
                  <Select
                    label="対象日"
                    value={summaryDayId}
                    onChange={(e) => setSummaryDayId(e.target.value)}
                  >
                    {DAYS.filter((d) => !d.closed).map((d) => (
                      <option key={d.id} value={d.id}>
                        {d.short}（{d.weekday}）
                      </option>
                    ))}
                  </Select>
                </div>
              </Cluster>
            </CardHeader>
            <CardContent>
              <VStack gap={4}>
                <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-6">
                  {STATUS_ORDER.map((status) => {
                    const meta = STATUS_META[status];
                    return (
                      <div
                        key={status}
                        className="flex flex-col gap-1 rounded-lg border border-border bg-card p-3"
                      >
                        <span className="text-xs text-muted-foreground">
                          <span aria-hidden className="mr-1">
                            {meta.glyph}
                          </span>
                          {meta.label}
                        </span>
                        <span className="text-2xl font-bold tabular-nums">
                          {daily[status]}
                        </span>
                      </div>
                    );
                  })}
                </div>
                <DistributionBar
                  segments={STATUS_ORDER.filter((s) => daily[s] > 0).map(
                    (status) => ({
                      label: STATUS_META[status].label,
                      value: daily[status],
                      color: STATUS_META[status].cellTone === "muted"
                        ? "muted"
                        : (STATUS_META[status].cellTone as
                            | "success"
                            | "destructive"
                            | "warning"
                            | "info"),
                    }),
                  )}
                  totalLabel="人数"
                  showLegend
                  formatValue={(v) => `${v} 名`}
                />
                <p className="text-sm text-muted-foreground">
                  {summaryDay?.short}（{summaryDay?.weekday}）: 在籍{" "}
                  {daily.total} 名中、出席 {daily.present} 名・欠席{" "}
                  {daily.absent} 名・遅刻 {daily.late} 名
                </p>
              </VStack>
            </CardContent>
          </Card>
        </section>
      </VStack>

      {/* ===== 出欠入力シート ===== */}
      <Sheet
        open={selected !== null}
        onOpenChange={(open) => {
          if (!open) closeSheet();
        }}
      >
        <SheetContent side="right" className="flex flex-col gap-4 overflow-y-auto">
          <SheetHeader>
            <SheetTitle>出欠の入力</SheetTitle>
            <SheetDescription>
              {selectedStudent
                ? `${selectedStudent.name}（${selectedDay?.short} ${selectedDay?.weekday}曜日）`
                : ""}
            </SheetDescription>
          </SheetHeader>

          <div className="flex flex-col gap-5">
            <fieldset className="flex flex-col gap-2">
              <legend className="text-sm font-medium">出欠区分</legend>
              <ToggleGroup
                type="single"
                value={draftStatus}
                onValueChange={(v) => {
                  if (v) setDraftStatus(v as AttendanceStatus);
                }}
                disallowEmpty
                variant="outline"
                className="flex-wrap justify-start"
                aria-label="出欠区分を選択"
              >
                {STATUS_ORDER.map((status) => {
                  const meta = STATUS_META[status];
                  return (
                    <ToggleGroupItem
                      key={status}
                      value={status}
                      aria-label={meta.label}
                    >
                      <span aria-hidden className="mr-1">
                        {meta.glyph}
                      </span>
                      {meta.label}
                    </ToggleGroupItem>
                  );
                })}
              </ToggleGroup>
            </fieldset>

            {draftNeedsNote ? (
              <div className="flex flex-col gap-4 rounded-lg border border-border bg-muted/30 p-3">
                <p className="text-xs font-medium text-muted-foreground">
                  欠席連絡
                </p>
                <Select
                  label="理由"
                  value={draftReason}
                  onChange={(e) =>
                    setDraftReason(e.target.value as AbsenceReason | "")
                  }
                >
                  <option value="">（未選択）</option>
                  {REASON_ORDER.map((reason) => (
                    <option key={reason} value={reason}>
                      {REASON_LABEL[reason]}
                    </option>
                  ))}
                </Select>
                <Textarea
                  label="連絡メモ"
                  description="保護者からの連絡や対応状況を記録します"
                  placeholder="例: 発熱のためお休み。母より連絡。"
                  value={draftMemo}
                  onChange={(e) => setDraftMemo(e.target.value)}
                />
              </div>
            ) : (
              <p className="text-sm text-muted-foreground">
                出席を選ぶと連絡欄は不要です。
              </p>
            )}
          </div>

          <SheetFooter>
            <Button variant="outline" onClick={closeSheet}>
              キャンセル
            </Button>
            <Button onClick={saveDraft}>記録する</Button>
          </SheetFooter>
        </SheetContent>
      </Sheet>

      {STUDENTS.length === 0 ? (
        <EmptyState title="生徒が登録されていません" />
      ) : null}
    </Container>
  );
}

import type {
  AttendanceMap,
  AttendanceRecord,
  SchoolDay,
  Student,
} from "./types";

export const CLASS_LABEL = "2 年 B 組";

export const STUDENTS: Student[] = [
  { id: "s01", number: 1, name: "青木 陽斗", kana: "あおき はると" },
  { id: "s02", number: 2, name: "石田 美咲", kana: "いしだ みさき" },
  { id: "s03", number: 3, name: "大野 結菜", kana: "おおの ゆいな" },
  { id: "s04", number: 4, name: "加藤 蓮", kana: "かとう れん" },
  { id: "s05", number: 5, name: "木村 颯太", kana: "きむら そうた" },
  { id: "s06", number: 6, name: "斉藤 葵", kana: "さいとう あおい" },
  { id: "s07", number: 7, name: "田中 大翔", kana: "たなか ひろと" },
  { id: "s08", number: 8, name: "中村 さくら", kana: "なかむら さくら" },
  { id: "s09", number: 9, name: "橋本 凜", kana: "はしもと りん" },
  { id: "s10", number: 10, name: "山口 律", kana: "やまぐち りつ" },
];

// 2026 年 6 月の 2 週間（平日）。途中に運動会の振替休日を 1 日挟む。
export const DAYS: SchoolDay[] = [
  { id: "2026-06-01", short: "6/1", weekday: "月" },
  { id: "2026-06-02", short: "6/2", weekday: "火" },
  { id: "2026-06-03", short: "6/3", weekday: "水" },
  { id: "2026-06-04", short: "6/4", weekday: "木" },
  { id: "2026-06-05", short: "6/5", weekday: "金" },
  { id: "2026-06-08", short: "6/8", weekday: "月" },
  {
    id: "2026-06-09",
    short: "6/9",
    weekday: "火",
    closed: true,
    closedLabel: "振替休日",
  },
  { id: "2026-06-10", short: "6/10", weekday: "水" },
  { id: "2026-06-11", short: "6/11", weekday: "木" },
  { id: "2026-06-12", short: "6/12", weekday: "金" },
];

const r = (
  status: AttendanceRecord["status"],
  note?: AttendanceRecord["note"],
): AttendanceRecord => ({ status, note });

// 既定はすべて出席。例外のみ上書きする。
function buildRecords(): AttendanceMap {
  const map: AttendanceMap = {};
  for (const student of STUDENTS) {
    map[student.id] = {};
    for (const day of DAYS) {
      if (day.closed) continue; // 休校日は記録しない
      map[student.id][day.id] = r("present");
    }
  }

  // --- 個別のケース ---

  // 橋本 凜 (s09): 慢性的な欠席 — 要注意になるはず
  map.s09["2026-06-01"] = r("absent", { reason: "sick", memo: "腹痛のため終日お休み（母より連絡）" });
  map.s09["2026-06-02"] = r("absent", { reason: "sick" });
  map.s09["2026-06-03"] = r("late", { reason: "sick", memo: "通院後 3 限から登校" });
  map.s09["2026-06-08"] = r("absent", { reason: "family", memo: "家庭の事情。担任から放課後に電話予定" });
  map.s09["2026-06-11"] = r("absent", { reason: "sick" });

  // 田中 大翔 (s07): 遅刻が多い
  map.s07["2026-06-02"] = r("late", { reason: "transport", memo: "電車遅延（遅延証明あり）" });
