import { STATUS_META } from "./statusMeta";
import type {
  AttendanceMap,
  DailySummary,
  SchoolDay,
  Student,
  StudentStats,
} from "./types";

/** 1 人分の集計。算入対象 = 公欠・出席停止・休校を除いた授業日数。 */
export function computeStudentStats(
  studentId: string,
  records: AttendanceMap,
  days: SchoolDay[],
): StudentStats {
  const row = records[studentId] ?? {};
  let present = 0;
  let absent = 0;
  let late = 0;
  let earlyLeave = 0;
  let official = 0;
  let suspended = 0;
  let countedDays = 0;

  for (const day of days) {
    if (day.closed) continue;
    const rec = row[day.id];
    if (!rec) continue;
    switch (rec.status) {
      case "present":
        present += 1;
        break;
      case "absent":
        absent += 1;
        break;
      case "late":
        late += 1;
        break;
      case "earlyLeave":
        earlyLeave += 1;
        break;
      case "official":
        official += 1;
        break;
      case "suspended":
        suspended += 1;
        break;
    }
    if (STATUS_META[rec.status].countsTowardRate) countedDays += 1;
  }

  // 出席率: 遅刻・早退は「登校はした」ので出席に算入（半欠扱いはしない単純モデル）。
  const attended = present + late + earlyLeave;
  const attendanceRate =
    countedDays > 0 ? Math.round((attended / countedDays) * 1000) / 10 : null;

  const atRisk =
    (attendanceRate !== null && attendanceRate < 90) || absent >= 3;

  return {
    countedDays,
    present,
    absent,
    late,
    earlyLeave,
    official,
    suspended,
    attendanceRate,
    atRisk,
  };
}

/** ある日のクラス全体のサマリ。 */
export function computeDailySummary(
  dayId: string,
  records: AttendanceMap,
  students: Student[],
): DailySummary {
  const summary: DailySummary = {
    present: 0,
    absent: 0,
    late: 0,
    earlyLeave: 0,
    official: 0,
    suspended: 0,
    recorded: 0,
    total: students.length,
  };
  for (const student of students) {
    const rec = records[student.id]?.[dayId];
    if (!rec) continue;
    summary.recorded += 1;
    summary[rec.status] += 1;
  }
  return summary;
}

