/** 出欠区分。色だけに依存せず、記号 + 文字で識別できるようにする。 */
export type AttendanceStatus =
  | "present" // 出席
  | "absent" // 欠席
  | "late" // 遅刻
  | "earlyLeave" // 早退
  | "official" // 公欠（忌引・出席停止以外の認められた欠席）
  | "suspended"; // 出席停止

/** 欠席・遅刻・早退に添える連絡（保護者連絡など）。 */
export interface AttendanceNote {
  /** 連絡理由のカテゴリ。 */
  reason?: AbsenceReason;
  /** 自由記述メモ。 */
  memo?: string;
}

export type AbsenceReason =
  | "sick" // 体調不良
  | "fever" // 発熱
  | "injury" // けが・通院
  | "family" // 家庭の事情
  | "bereavement" // 忌引
  | "infection" // 出席停止（インフル等）
  | "transport" // 交通機関の遅延
  | "other"; // その他

/** 1 セル = ある生徒 × ある日付 の状態。 */
export interface AttendanceRecord {
  status: AttendanceStatus;
  note?: AttendanceNote;
}

export interface Student {
  id: string;
  /** 出席番号。 */
  number: number;
  name: string;
  kana: string;
}

export interface SchoolDay {
  id: string; // ISO 日付 (YYYY-MM-DD)
  /** "6/2" などの短い表示。 */
  short: string;
  /** 曜日 (月〜金)。 */
  weekday: string;
  /** 学校がある日でない（休校・行事等）場合 true。 */
  closed?: boolean;
  /** 休校理由（行事名など）。 */
  closedLabel?: string;
}

/** records[studentId][dayId] = AttendanceRecord */
export type AttendanceMap = Record<string, Record<string, AttendanceRecord>>;

export interface StudentStats {
  /** 算入対象（公欠・出席停止・休校を除いた授業日数）。 */
  countedDays: number;
  present: number;
  absent: number;
  late: number;
  earlyLeave: number;
  official: number;
  suspended: number;
  /** 出席率 (%) — present / countedDays。算入対象が 0 のときは null。 */
  attendanceRate: number | null;
  /** 要注意フラグ（出席率 < 90% または 欠席 3 回以上）。 */
  atRisk: boolean;
}

export interface DailySummary {
  present: number;
  absent: number;
  late: number;
  earlyLeave: number;
  official: number;
  suspended: number;
  /** その日に記録のある生徒数（算入対象）。 */
  recorded: number;
  total: number;
}
